t.script:
(function () {
    'use strict';

    var todayStr = new Date().toISOString().split('T')[0];
    var dateInput  = document.getElementById('date');
    var timeSelect = document.getElementById('start_time');
    var findBtn    = document.getElementById('findTablesBtn');
    var searchForm = document.getElementById('searchForm');

    // Set minimum date to today
    if (dateInput) {
        dateInput.setAttribute('min', todayStr);
    }

    function isPastDateTime() {
        if (!dateInput || !timeSelect) return false;
        var selectedDate = dateInput.value;
        var selectedHour = parseFloat(timeSelect.value);
        if (!selectedDate) return false;

        var now = new Date();
        var nowDate = now.toISOString().split('T')[0];
        var nowHour = now.getHours() + now.getMinutes() / 60;

        if (selectedDate < nowDate) return true;  // Past date
        if (selectedDate === nowDate && selectedHour <= nowHour) return true;  // Same day, past time
        return false;
    }

    function validateAndSubmit(e) {
        var dateErr = document.getElementById('date-error');
        var timeErr = document.getElementById('time-error');
        var valid = true;

        // Hide previous errors
        dateErr.classList.remove('show');
        timeErr.classList.remove('show');

        if (isPastDateTime()) {
            var selectedDate = dateInput ? dateInput.value : '';
            var nowDate = new Date().toISOString().split('T')[0];
            if (selectedDate < nowDate) {
                dateErr.classList.add('show');
            } else {
                timeErr.classList.add('show');
            }
            e.preventDefault();
            valid = false;
        }
        return valid;
    }

    if (searchForm) {
        searchForm.addEventListener('submit', validateAndSubmit);
    }

    // Re-validate when date or time changes
    if (dateInput) {
        dateInput.addEventListener('change', function () {
            document.getElementById('date-error').classList.remove('show');
            document.getElementById('time-error').classList.remove('show');
        });
    }
    if (timeSelect) {
        timeSelect.addEventListener('change', function () {
            document.getElementById('time-error').classList.remove('show');
        });
    }

    // --- Multi-table selection capacity counter and validation ---
    var checkboxes = document.querySelectorAll('.table-checkbox-input');
    var capacityBadge = document.getElementById('capacity-badge');
    var errorDiv = document.getElementById('table-selection-error');
    var bookingForm = document.getElementById('bookingForm');
    var guestCountInput = document.getElementById('guest_count');

    function updateCapacity() {
        var totalSeats = 0;
        var checkedCount = 0;
        var guestCount = parseInt(guestCountInput ? guestCountInput.value : 0) || 2;

        checkboxes.forEach(function(cb) {
            if (cb.checked) {
                totalSeats += parseInt(cb.getAttribute('data-seats')) || 0;
                checkedCount++;
            }
        });

        if (capacityBadge) {
            capacityBadge.textContent = 'Selected seats: ' + totalSeats + ' / ' + guestCount + ' guests';
            if (totalSeats >= guestCount && checkedCount > 0) {
                capacityBadge.className = 'badge bg-success';
            } else {
                capacityBadge.className = 'badge bg-danger';
            }
        }
    }

    checkboxes.forEach(function(cb) {
        cb.addEventListener('change', updateCapacity);
    });

    if (bookingForm) {
        bookingForm.addEventListener('submit', function(e) {
            var totalSeats = 0;
            var checkedCount = 0;
            var guestCount = parseInt(guestCountInput ? guestCountInput.value : 0) || 2;

            checkboxes.forEach(function(cb) {
                if (cb.checked) {
                    totalSeats += parseInt(cb.getAttribute('data-seats')) || 0;
                    checkedCount++;
                }
            });

            if (checkedCount === 0) {
                if (errorDiv) {
                    errorDiv.textContent = 'Please select at least one table.';
                    errorDiv.style.display = 'block';
                    errorDiv.scrollIntoView({ behavior: 'smooth' });
                }
                e.preventDefault();
                return false;
            }

            if (totalSeats < guestCount) {
                if (errorDiv) {
                    errorDiv.textContent = 'The selected table(s) only seat ' + totalSeats + ' guests. You need at least ' + guestCount + ' seats. Please select additional tables.';
                    errorDiv.style.display = 'block';
                    errorDiv.scrollIntoView({ behavior: 'smooth' });
                }
                e.preventDefault();
                return false;
            }

            if (errorDiv) {
                errorDiv.style.display = 'none';
            }
        });
    }

    // Run once on load to initialize badge state
    updateCapacity();
})();
